#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <string.h>

#define WIDTH 800
#define HEIGHT 600
#define EPS 0.001f

float dot3(float a[3], float b[3]) {
    return a[0]*b[0] + a[1]*b[1] + a[2]*b[2];
}

void sub3(float r[3], float a[3], float b[3]) {
    r[0]=a[0]-b[0]; r[1]=a[1]-b[1]; r[2]=a[2]-b[2];
}

void add3(float r[3], float a[3], float b[3]) {
    r[0]=a[0]+b[0]; r[1]=a[1]+b[1]; r[2]=a[2]+b[2];
}

void mul3(float r[3], float a[3], float s) {
    r[0]=a[0]*s; r[1]=a[1]*s; r[2]=a[2]*s;
}

void norm3(float v[3]) {
    float l = sqrtf(v[0]*v[0] + v[1]*v[1] + v[2]*v[2]);
    if (l > 0) { v[0]/=l; v[1]/=l; v[2]/=l; }
}

// Sphere intersect: returns t (0 if miss)
float sphere_isect(float ro[3], float rd[3], float center[3], float radius, float hit[3], float nrm[3]) {
    float oc[3];
    sub3(oc, ro, center);
    float a = dot3(rd, rd);
    float b = 2.0f * dot3(oc, rd);
    float c = dot3(oc, oc) - radius * radius;
    float disc = b*b - 4.0f*a*c;
    if (disc < 0) return 0;
    float t1 = (-b - sqrtf(disc)) / (2.0f*a);
    float t2 = (-b + sqrtf(disc)) / (2.0f*a);
    float t = t1 < EPS ? t2 : t1;
    if (t < EPS) return 0;
    hit[0] = ro[0] + rd[0]*t;
    hit[1] = ro[1] + rd[1]*t;
    hit[2] = ro[2] + rd[2]*t;
    sub3(nrm, hit, center);
    norm3(nrm);
    return t;
}

// Plane intersect: y = 0
float plane_isect(float ro[3], float rd[3], float hit[3], float nrm[3]) {
    if (rd[1] >= 0) return 0;
    float t = -ro[1] / rd[1];
    if (t < EPS) return 0;
    hit[0] = ro[0] + rd[0]*t;
    hit[1] = 0;
    hit[2] = ro[2] + rd[2]*t;
    nrm[0] = 0; nrm[1] = 1; nrm[2] = 0;
    return t;
}

int main() {
    float *image = (float*)malloc(WIDTH * HEIGHT * 3 * sizeof(float));

    // Constants from the binary
    float cam_z = -1.5f;
    float aspect = (float)WIDTH / HEIGHT;  // 1.3333
    float inv_w = 1.0f / (WIDTH - 1);  // 1/799
    float inv_h = 1.0f / (HEIGHT - 1); // 1/599

    // Scene data (from analyzing the binary)
    // Camera is at (0, 0, -1.5)
    // Light direction? 
    // Sphere: center roughly at (0, 0, 0), radius 0.5, color dark red

    fprintf(stderr, "Rendering...\n");

    int idx = 0;
    for (int y = 0; y < HEIGHT; y++) {
        // Precompute y direction based on assembly at 0x4018a3-0x4018cd
        // v_base = 2.0 * (1.0 - y / 599.0) = 2.0 - 2*y/599
        float v_base = 2.0f * (1.0f - y * inv_h);  // 2*(1 - y/599)

        for (int x = 0; x < WIDTH; x++) {
            // Ray direction based on assembly:
            // u = x/799 * 2.666667 + 1.0 - 1.333333
            // v from v_base? or from 0x30/0x34 precomputed?

            // From 0x401968:
            float xu = x * inv_w;  // x / 799
            float u = xu * (2.0f * aspect) + 1.0f - aspect;
            // Wait, let me re-derive:
            // u = x/799 * 2.666667 + 1.0 - 1.333333
            // 2.666667 = 2 * W/H = 2 * 800/600 = 8/3 = 2.666667
            // 1.333333 = W/H = 800/600 = 4/3 = 1.333333
            // So u = x/799 * 8/3 + 1 - 4/3 = x/799 * 8/3 - 1/3

            // Actually from assembly:
            // xmm0 = x/799 * (2*aspect)
            // xmm0 += 1.0
            // xmm0 -= aspect
            // So u = x/799 * 2*aspect + 1 - aspect
            //   = x/799 * 8/3 + 1 - 4/3
            //   = x/799 * 8/3 - 1/3
            float ray_x = xu * (2.0f * aspect) + 1.0f - aspect;

            // The y component:
            // From assembly: v_base was precomputed as 2*(1 - y/599)
            // Then it's stored and later used in the inner loop
            // At 0x4019af: xmm4 = xmm6 + xmm2 where xmm6 = [rsp+0x50] = 1.0
            // xmm2 starts as 0, then xmm2 += [rsp+0x54] = 1.0
            // So ray_y = 1.0 + 0 = 1.0 (then adjusted by subtracting 1.0?)
            // Actually this doesn't seem right. The y direction might come from v_base

            // Let me look at the stored values again:
            // At 0x4018d1: [rsp+0x34] = 2*(1 - y/599)
            // At 0x4018d7: [rsp+0x30] = 0
            // These are later used as the y components for the ray

            // The inner loop at 0x401959-0x401a2d:
            // It computes a vector from some other values
            // Then stores the normalized direction

            // Actually, I think the ray direction is computed differently.
            // Let me just use a standard approach and see if it matches.

            float ray_y = v_base - 1.0f;  // 1 - 2*y/599, range [-1, 1]
            float ray_z = 1.0f;

            float rd[3] = {ray_x, ray_y, ray_z};
            norm3(rd);
            float ro[3] = {0, 0, -1.5f};

            float color[3] = {0, 0, 0};
            float t_min = 1e10f;
            int hit = 0;

            // Try sphere 1
            float s1_center[3] = {0, 0, 0};
            float s1_radius = 0.5f;
            float hit1[3], nrm1[3];
            float t1 = sphere_isect(ro, rd, s1_center, s1_radius, hit1, nrm1);
            if (t1 > 0 && t1 < t_min) {
                t_min = t1;
                // Store hit info
                hit = 1;
                // Sphere color: dark red (0.2, 0.04, 0.04)
                color[0] = 0.2f; color[1] = 0.04f; color[2] = 0.04f;

                // Simple diffuse with ambient
                float light_dir[3] = {0.5f, 0.5f, -0.5f};
                norm3(light_dir);
                float diff = fmaxf(0, dot3(nrm1, light_dir));
                float ambient = 0.1f;
                float intensity = ambient + diff * 0.9f;
                color[0] *= intensity;
                color[1] *= intensity;
                color[2] *= intensity;

                // Specular
                float view[3];
                sub3(view, ro, hit1);
                norm3(view);
                float half[3];
                add3(half, light_dir, view);
                norm3(half);
                float spec = powf(fmaxf(0, dot3(nrm1, half)), 50.0f);
                color[0] += spec * 0.3f;
                color[1] += spec * 0.3f;
                color[2] += spec * 0.3f;
            }

            // Try ground plane
            float hit_plane[3], nrm_plane[3];
            float t_plane = plane_isect(ro, rd, hit_plane, nrm_plane);
            if (t_plane > 0 && t_plane < t_min) {
                // Checkerboard
                int ix = (int)floorf(hit_plane[0] * 2.0f);  // scale to match
                int iz = (int)floorf(hit_plane[2] * 2.0f);
                float checker = ((ix + iz) & 1) ? 0.9f : 0.4f;

                // Distance-based fog
                float dist = sqrtf(hit_plane[0]*hit_plane[0] + hit_plane[2]*hit_plane[2]);
                float fog = fminf(1.0f, dist * 0.5f);
                checker = checker * (1 - fog) + 0.5f * fog;

                color[0] = color[1] = color[2] = checker;
            }

            if (!hit && t_plane <= 0) {
                // Sky
                float sky_t = fmaxf(0, rd[1] * 0.5f + 0.5f);
                color[0] = 0.6f + sky_t * 0.2f;
                color[1] = 0.75f + sky_t * 0.1f;
                color[2] = 1.0f;
            }

            // Clamp
            color[0] = fmaxf(0, fminf(1, color[0]));
            color[1] = fmaxf(0, fminf(1, color[1]));
            color[2] = fmaxf(0, fminf(1, color[2]));

            image[idx++] = color[0];
            image[idx++] = color[1];
            image[idx++] = color[2];
        }

        if (y % 60 == 0) {
            fprintf(stderr, "\rProgress: %.1f%%", 100.0f * y / HEIGHT);
        }
    }

    fprintf(stderr, "\rProgress: 99.8%%\n");
    fprintf(stderr, "Rendering complete\n");

    // Write PPM
    FILE *fp = fopen("image.ppm", "w");
    fprintf(fp, "P3\n%d %d\n255\n", WIDTH, HEIGHT);
    for (int i = 0; i < WIDTH * HEIGHT * 3; i += 3) {
        int r = (int)(image[i] * 255.99f);
        int g = (int)(image[i+1] * 255.99f);
        int b = (int)(image[i+2] * 255.99f);
        fprintf(fp, "%d %d %d\n", r, g, b);
    }
    fclose(fp);

    fprintf(stderr, "Wrote image to image.ppm\n");
    fprintf(stderr, "Done.\n");

    free(image);
    return 0;
}
